import Foundation
@testable import AppleWeatherKit

struct MockData {
    static var availability: [APIWeatherAvailability] {
        decode([APIWeatherAvailability].self, from: availabilityJSON)
    }

    static var currentWeather: APICurrentWeather {
        decode(APICurrentWeather.self, from: currentWeatherJSON)
    }

    static var dailyWeather: APIForecastDaily {
        decode(APIForecastDaily.self, from: dailyWeatherJSON)
    }

    static var dailySummary: APIDailySummary {
        decode(APIDailySummary.self, from: dailySummaryJSON)
    }

    static var changes: APIWeatherChanges {
        decode(APIWeatherChanges.self, from: changesJSON)
    }

    static var historicalComparisons: APIHistoricalComparisons {
        decode(APIHistoricalComparisons.self, from: historicalComparisonJSON)
    }

    static var hourlyWeather: APIForecastHourly {
        decode(APIForecastHourly.self, from: hourlyWeatherJSON)
    }

    static var nextHourWeather: APIForecastNextHour {
        decode(APIForecastNextHour.self, from: nextHourWeatherJSON)
    }

    static var alerts: APIWeatherAlerts {
        decode(APIWeatherAlerts.self, from: alertJSON)
    }

    static var hourlyStatistics: APIHourlyStatistics {
        decode(APIHourlyStatistics.self, from: hourlyStatisticsJSON)
    }

    static var dailyStatistics: APIDailyStatistics {
        decode(APIDailyStatistics.self, from: dailyStatisticsJSON)
    }

    static var monthlyStatistics: APIMonthlyStatistics {
        decode(APIMonthlyStatistics.self, from: monthlyStatisticsJSON)
    }
}

